import asyncio
import json
from websockets import serve, WebSocketServerProtocol

class Player:
    def __init__(self):
        self.items = {}  # item_id : quantity

    def add_item(self, item_id, quantity=1):
        if item_id in self.items:
            self.items[item_id] += quantity
        else:
            self.items[item_id] = quantity

    async def handle(self, websocket: WebSocketServerProtocol, path: str):
        # Register new player
        players[websocket] = Player()

        try:
            # Receive messages from client and broadcast them to all other clients
            async for message in websocket:
                data = json.loads(message)
                action = data['action']
                item_id = data['item_id']
                
                if action == 'add':
                    players[websocket].add_item(item_id, quantity=1)
                elif action == 'remove':
                    if item_id in players[websocket].items:
                        players[websocket].items[item_id] -= 1
                        if players[websocket].items[item_id] == 0:
                            del players[websocket].items[item_id]
                
                # Broadcast to all other clients
                for ws in players:
                    if ws != websocket:
                        await ws.send(message)
        finally:
            # Unregister player on disconnect
            del players[websocket]

async def main():
    async with serve('localhost', 8765, serve_forever=False):
        await start_server

